# Golden record versioning and chunked AI context
from dataclasses import dataclass, field
from typing import List, Dict, Any, Optional
from datetime import datetime, timezone
import hashlib, json

@dataclass
class GoldenRecord:
    golden_id: str
    entity_type: str
    entity_id: str
    attributes: Dict[str, Any]
    source_systems: List[str]
    survivorship_log: Dict[str, str]
    version: int
    created_at: datetime
    updated_at: datetime
    steward_email: str
    content_hash: str = ""

    def __post_init__(self):
        if not self.content_hash:
            payload = json.dumps(self.attributes, sort_keys=True)
            self.content_hash = hashlib.sha256(payload.encode()).hexdigest()[:16]

    def to_ai_context_chunks(self, strategy: str = "attribute_grouped") -> List[Dict]:
        base_meta = {
            "golden_id": self.golden_id,
            "entity_type": self.entity_type,
            "entity_id": self.entity_id,
            "golden_version": self.version,
            "updated_at": self.updated_at.isoformat(),
            "content_hash": self.content_hash,
            "steward": self.steward_email,
        }
        if strategy == "single":
            lines = [f"Entity: {self.entity_type} | ID: {self.entity_id}"]
            for attr, val in self.attributes.items():
                lines.append(f"{attr}: {val}")
            return [{"id": f"golden:{self.golden_id}:v{self.version}",
                     "content": "\n".join(lines), "metadata": base_meta}]

        # attribute_grouped strategy
        identity_attrs = {"name", "id", "sku", "code", "status"}
        commercial_attrs = {"price", "cost", "discount", "currency"}
        groups: Dict[str, dict] = {"identity": {}, "commercial": {}, "descriptive": {}}
        for attr, val in self.attributes.items():
            if attr in identity_attrs:
                groups["identity"][attr] = val
            elif attr in commercial_attrs:
                groups["commercial"][attr] = val
            else:
                groups["descriptive"][attr] = val

        chunks = []
        for group_name, attrs in groups.items():
            if not attrs:
                continue
            lines = [f"Entity: {self.entity_type} | {group_name}"]
            for a, v in attrs.items():
                lines.append(f"  {a}: {v}")
            chunks.append({
                "id": f"golden:{self.golden_id}:v{self.version}:{group_name}",
                "content": "\n".join(lines),
                "metadata": {**base_meta, "chunk_group": group_name}
            })
        return chunks

# Example
record = GoldenRecord(
    golden_id="GR-12345",
    entity_type="product",
    entity_id="PROD-789",
    attributes={
        "name": "Acme Widget Pro",
        "sku": "WGT-PRO-001",
        "price": 189.99,
        "currency": "USD",
        "description": "Professional-grade widget for enterprise use.",
        "category": "hardware",
        "status": "active"
    },
    source_systems=["erp", "crm", "marketing"],
    survivorship_log={"price": "erp", "name": "crm", "description": "marketing"},
    version=7,
    created_at=datetime(2026, 1, 1, tzinfo=timezone.utc),
    updated_at=datetime.now(timezone.utc),
    steward_email="alice@example.com"
)

chunks = record.to_ai_context_chunks(strategy="attribute_grouped")
for chunk in chunks:
    print(f"Chunk ID: {chunk['id']}")

# Golden record version store with rollback
from typing import Dict, List, Optional
from datetime import datetime, timezone

class GoldenRecordVersionStore:
    def __init__(self):
        self._store: Dict[str, List] = {}

    def _key(self, entity_type: str, entity_id: str) -> str:
        return f"{entity_type}:{entity_id}"

    def put(self, record) -> None:
        key = self._key(record.entity_type, record.entity_id)
        if key not in self._store:
            self._store[key] = []
        self._store[key].append(record)
        self._store[key].sort(key=lambda r: r.version, reverse=True)

    def get_latest(self, entity_type: str, entity_id: str):
        records = self._store.get(self._key(entity_type, entity_id), [])
        return records[0] if records else None

    def get_version(self, entity_type: str, entity_id: str, version: int):
        for r in self._store.get(self._key(entity_type, entity_id), []):
            if r.version == version:
                return r
        return None

    def rollback_to_version(self, entity_type: str, entity_id: str, version: int):
        target = self.get_version(entity_type, entity_id, version)
        if not target:
            raise ValueError(f"Version {version} not found for {entity_type}:{entity_id}")
        latest = self.get_latest(entity_type, entity_id)
        new_version = (latest.version + 1) if latest else 1
        import copy
        rolled_back = copy.deepcopy(target)
        rolled_back.version = new_version
        rolled_back.updated_at = datetime.now(timezone.utc)
        self.put(rolled_back)
        return rolled_back
